flow.set('arkteos_last_frame', Date.now());
flow.set('arkteos_connected', true);
return null;

const last = flow.get('arkteos_last_frame') || 0;
const connected = flow.get('arkteos_connected') || false;
const now = Date.now();
const elapsed = now - last;
const isConnected = last > 0 && elapsed < 30000;

if (isConnected !== connected) {
    flow.set('arkteos_connected', isConnected);
    msg.payload = isConnected ? 'ON' : 'OFF';
    msg.topic = 'arkteos/status/connected';
    return msg;
}
if (elapsed % 60000 < 15000) {
    msg.payload = isConnected ? 'ON' : 'OFF';
    msg.topic = 'arkteos/status/connected';
    return msg;
}
return null;

const buf = msg.payload;
if (!Buffer.isBuffer(buf) || buf.length === 0) return null;

const size = buf.length;

function read16s(b, i) {
    const v = b[i] + b[i + 1] * 256;
    return v >= 32768 ? v - 65536 : v;
}
function read16u(b, i) {
    return b[i] + b[i + 1] * 256;
}
function read8(b, i) {
    return b[i];
}
function signExtend8(x) {
    return (x ^ 0x80) - 0x80;
}

const STATUTS_PAC = { 0: 'Arret', 1: 'Attente', 2: 'Chaud', 3: 'Froid', 4: 'Hors Gel', 5: 'Ext Chaud', 6: 'Ext Froid', 7: 'Chaud Froid', 8: 'ECS', 9: 'Piscine' };
const STATUTS_FRIGO = { 0: 'Arret', 1: 'Refroidissement', 2: 'Chauffage', 3: 'Degivrage' };
const MODELES_PAC = { 0x10: 'AJPAC_III', 0x11: 'BAGUIO_ZURAN_IV', 0x12: 'TIMAX_III', 0x13: 'GEOTWIN_IV', 0x14: 'CAIROX', 0x15: 'PHOENIX', 0x16: 'ARKTEA', 0x17: 'GEOINVERTER', 0x18: 'LAST_MODEL' };

if (size === 163) {
    const statut_frigo_raw = buf[36] >> 4;
    const active_error_fri = buf[12] + (buf[13] & 0x0f) * 256;
    msg.payload = {
        frame_type: 'frigo',
        exterieur_temp:         read16s(buf, 24) / 10,
        nb_degivrages:          read16u(buf, 26),
        temps_compresseur:      read16u(buf, 40) / 10,
        nb_cycles_compresseur:  read16u(buf, 42) * 100,
        freq_comp_actuelle:     read16u(buf, 52),
        freq_comp_cible:        read16u(buf, 54),
        fan_speed_evaporator_1: read16u(buf, 56),
        dc_voltage:             read16u(buf, 62),
        statut_frigo:           statut_frigo_raw,
        statut_frigo_s:         STATUTS_FRIGO[statut_frigo_raw] || 'Inconnu',
        active_error_fri:       active_error_fri
    };
    return msg;
}

if (size === 227) {
    const statut_pac_raw = buf[12] & 0b11111;
    const modele_raw = buf[46];
    const active_error_reg = buf[30] + (buf[31] & 0x0f) * 256;
    const signal_rf = signExtend8(buf[193]);
    msg.payload = {
        frame_type: 'regulation',
        puissance_inst_produite:          read16u(buf, 16) / 0.1,
        puissance_inst_consommee:         read16u(buf, 18) / 0.1,
        temps_mise_sous_tension:          read16u(buf, 20),
        modele_pac:                       modele_raw,
        modele_pac_s:                     MODELES_PAC[modele_raw] || 'Inconnu',
        primaire_temp_eau_aller_consigne: read16s(buf, 52) / 10,
        primaire_temp_eau_aller:          read16s(buf, 54) / 10,
        primaire_temp_eau_retour:         read16s(buf, 56) / 10,
        primaire_debit_eau:               read16u(buf, 60) / 10,
        primaire_pression:                read8(buf, 62) / 10,
        primaire_circulateur_consigne:    read8(buf, 64),
        zone1_temp_interieur:             read16s(buf, 68) / 10,
        zone1_consigne:                   read16s(buf, 70) / 10,
        ecs_temp_eau_milieu:              read16s(buf, 108) / 10,
        ecs_temp_eau_bas:                 read16s(buf, 110) / 10,
        ecs_consigne:                     read16s(buf, 122) / 10,
        nb_cycles_compresseur_reg:        read16u(buf, 148),
        statut_pac:                       statut_pac_raw,
        statut_pac_s:                     STATUTS_PAC[statut_pac_raw] || 'Inconnu',
        active_error_reg:                 active_error_reg,
        signal_rf_sonde_1:                signal_rf
    };
    return msg;
}

return null;

const data = msg.payload;

const RANGES = {
    exterieur_temp:                   { min: -50,   max: 150 },
    nb_degivrages:                    { min: 0,     max: 99999 },
    temps_compresseur:                { min: 0,     max: 999999 },
    nb_cycles_compresseur:            { min: 0,     max: 9999999 },
    freq_comp_actuelle:               { min: 0,     max: 200 },
    freq_comp_cible:                  { min: 0,     max: 200 },
    fan_speed_evaporator_1:           { min: 0,     max: 3000 },
    dc_voltage:                       { min: 0,     max: 1000 },
    statut_frigo:                     { min: 0,     max: 3 },
    active_error_fri:                 { min: 0,     max: 65535 },
    puissance_inst_produite:          { min: 0,     max: 50000 },
    puissance_inst_consommee:         { min: 0,     max: 50000 },
    temps_mise_sous_tension:          { min: 0,     max: 999999 },
    primaire_temp_eau_aller_consigne: { min: -10,   max: 90 },
    primaire_temp_eau_aller:          { min: -10,   max: 90 },
    primaire_temp_eau_retour:         { min: -10,   max: 90 },
    primaire_debit_eau:               { min: 0,     max: 10000 },
    primaire_pression:                { min: 0,     max: 10 },
    primaire_circulateur_consigne:    { min: 0,     max: 100 },
    zone1_temp_interieur:             { min: -10,   max: 50 },
    zone1_consigne:                   { min: 5,     max: 35 },
    ecs_temp_eau_milieu:              { min: 0,     max: 95 },
    ecs_temp_eau_bas:                 { min: 0,     max: 95 },
    ecs_consigne:                     { min: 0,     max: 80 },
    nb_cycles_compresseur_reg:        { min: 0,     max: 999999 },
    statut_pac:                       { min: 0,     max: 9 },
    active_error_reg:                 { min: 0,     max: 65535 },
    signal_rf_sonde_1:                { min: -128,  max: 127 }
};

const filtered = { frame_type: data.frame_type };
const rejected = {};

for (const [key, val] of Object.entries(data)) {
    if (key === 'frame_type') continue;
    // Valeurs texte : pas de filtre de plage
    if (typeof val === 'string') {
        filtered[key] = val;
        continue;
    }
    const range = RANGES[key];
    if (!range) {
        filtered[key] = val;
        continue;
    }
    if (val >= range.min && val <= range.max) {
        filtered[key] = val;
    } else {
        rejected[key] = val;
    }
}

if (Object.keys(rejected).length > 0) {
    node.warn('Valeurs aberrantes filtrées : ' + JSON.stringify(rejected));
}

msg.payload = filtered;
return msg;

const THRESHOLDS = {
    exterieur_temp:         0.5,
    nb_degivrages:          1,
    temps_compresseur:      1,
    nb_cycles_compresseur:  100,
    freq_comp_actuelle:     1,
    freq_comp_cible:        1,
    fan_speed_evaporator_1: 10,
    dc_voltage:             5,
    statut_frigo:           1,
    active_error_fri:       1
};
const MAX_INTERVALS = {
    exterieur_temp:         60000,
    nb_degivrages:          300000,
    temps_compresseur:      300000,
    nb_cycles_compresseur:  300000,
    freq_comp_actuelle:     30000,
    freq_comp_cible:        30000,
    fan_speed_evaporator_1: 30000,
    dc_voltage:             60000,
    statut_frigo:           60000,
    active_error_fri:       60000
};

const now = Date.now();
const prev = context.get('prev') || {};
const lastPublished = context.get('lastPublished') || {};
const data = msg.payload;
const toPublish = {};

for (const key of Object.keys(THRESHOLDS)) {
    const val = data[key];
    if (val === undefined) continue;
    const prevVal = prev[key];
    const lastTs = lastPublished[key] || 0;
    const isString = typeof val === 'string';
    const delta = isString ? (val !== prevVal ? Infinity : 0) : (prevVal !== undefined ? Math.abs(val - prevVal) : Infinity);
    const elapsed = now - lastTs;
    if (delta >= THRESHOLDS[key] || elapsed >= MAX_INTERVALS[key]) {
        toPublish[key] = val;
        lastPublished[key] = now;
        prev[key] = val;
    }
}

// Toujours inclure statut_frigo_s si statut_frigo change
if (toPublish.statut_frigo !== undefined) {
    toPublish.statut_frigo_s = data.statut_frigo_s;
}

context.set('prev', prev);
context.set('lastPublished', lastPublished);

if (Object.keys(toPublish).length === 0) return null;

msg.payload = Object.assign({ frame_type: 'frigo' }, toPublish);
return msg;

const THRESHOLDS = {
    puissance_inst_produite:          10,
    puissance_inst_consommee:         10,
    temps_mise_sous_tension:          1,
    primaire_temp_eau_aller_consigne: 0.5,
    primaire_temp_eau_aller:          0.5,
    primaire_temp_eau_retour:         0.5,
    primaire_debit_eau:               1,
    primaire_pression:                0.1,
    primaire_circulateur_consigne:    1,
    zone1_temp_interieur:             0.5,
    zone1_consigne:                   0.5,
    ecs_temp_eau_milieu:              0.5,
    ecs_temp_eau_bas:                 0.5,
    ecs_consigne:                     0.5,
    nb_cycles_compresseur_reg:        1,
    modele_pac:                       1,
    statut_pac:                       1,
    active_error_reg:                 1,
    signal_rf_sonde_1:                1
};
const MAX_INTERVALS = {
    puissance_inst_produite:          30000,
    puissance_inst_consommee:         30000,
    temps_mise_sous_tension:          300000,
    primaire_temp_eau_aller_consigne: 60000,
    primaire_temp_eau_aller:          60000,
    primaire_temp_eau_retour:         60000,
    primaire_debit_eau:               60000,
    primaire_pression:                60000,
    primaire_circulateur_consigne:    60000,
    zone1_temp_interieur:             60000,
    zone1_consigne:                   60000,
    ecs_temp_eau_milieu:              60000,
    ecs_temp_eau_bas:                 60000,
    ecs_consigne:                     60000,
    nb_cycles_compresseur_reg:        300000,
    modele_pac:                       3600000,
    statut_pac:                       60000,
    active_error_reg:                 60000,
    signal_rf_sonde_1:                300000
};

const now = Date.now();
const prev = context.get('prev') || {};
const lastPublished = context.get('lastPublished') || {};
const data = msg.payload;
const toPublish = {};

for (const key of Object.keys(THRESHOLDS)) {
    const val = data[key];
    if (val === undefined) continue;
    const prevVal = prev[key];
    const lastTs = lastPublished[key] || 0;
    const delta = prevVal !== undefined ? Math.abs(val - prevVal) : Infinity;
    const elapsed = now - lastTs;
    if (delta >= THRESHOLDS[key] || elapsed >= MAX_INTERVALS[key]) {
        toPublish[key] = val;
        lastPublished[key] = now;
        prev[key] = val;
    }
}

// Toujours inclure statut_pac_s et modele_pac_s si les valeurs numériques changent
if (toPublish.statut_pac !== undefined) {
    toPublish.statut_pac_s = data.statut_pac_s;
}
if (toPublish.modele_pac !== undefined) {
    toPublish.modele_pac_s = data.modele_pac_s;
}

context.set('prev', prev);
context.set('lastPublished', lastPublished);

if (Object.keys(toPublish).length === 0) return null;

msg.payload = Object.assign({ frame_type: 'regulation' }, toPublish);
return msg;

const data = msg.payload;
const topics = {
    exterieur_temp:         'arkteos/frigo/exterieur_temp',
    nb_degivrages:          'arkteos/frigo/nb_degivrages',
